def main_run(results, gap=2):
    """Pick the contiguous block of athlete detections with the most mass.

    The real run across the frame is a long, contiguous, high-area block;
    stray noise blobs form short low-area blocks elsewhere.
    """
    valid = [i for i, (a, b, cx) in enumerate(results) if a > 0]
    if not valid:
        return []
    blocks = []
    cur = [valid[0]]
    for i in valid[1:]:
        if i - cur[-1] <= gap:
            cur.append(i)
        else:
            blocks.append(cur)
            cur = [i]
    blocks.append(cur)
    # Score by total blob area (mass) over the block.
    def mass(block):
        return sum(results[i][0] for i in block)
    return max(blocks, key=mass)


